#include<bits/stdc++.h>
using namespace std;

struct task {
	int x, y;
} t[100100];
bool cmp(task a, task b) {
    if(a.x-a.y!=b.x-b.y)return a.x-a.y<b.x-b.y;
	return a.y < b.y;
}
int n;
int main() {
	cin >> n;
	for(int i=1;i<=n;i++){
		cin>>t[i].x>>t[i].y;
	}
	sort(t+1,t+n+1,cmp);
	for(int i=0;i+1;i++){
		int x=i;
		bool flag=1;
		for(int j=1;j<=n;j++){
			if(x+t[j].y<t[j].x){
				flag=0;
				break;
			}else{
				x+=t[j].y;
			}
		}
		if(flag){
			cout<<x;
			return 0;
		}
	}
	return 0;
}
